const zoneName = env.get('zone_name');
const chip = Number(env.get('chip'));
const pin = Number(env.get('pin'));
const expected = Number(env.get('expected_state'));
const helperPath = env.get('helper_path');

if (!helperPath) { node.error('helper_path env var must be set', msg); return null; }
if (![0, 1].includes(expected)) { node.error('expected_state must be 0 or 1', msg); return null; }
if (isNaN(chip) || chip < 0 || chip > 7) { node.error('chip must be 0-7', msg); return null; }
if (isNaN(pin) || pin < 0 || pin > 15) { node.error('pin must be 0-15', msg); return null; }

msg._cfg = { zoneName, chip, pin, expected };
msg.payload = `python3 ${helperPath} read --chip ${chip} --pin ${pin}`;
return msg;

const rc = msg.rc && typeof msg.rc.code === 'number' ? msg.rc.code : null;
const text = (typeof msg.payload === 'string') ? msg.payload : '';

if (rc === null) {
    msg._buf = (msg._buf || '') + text;
    return null;
}

const output = (msg._buf || '').trim();
const cfg = msg._cfg;

try {
    const result = JSON.parse(output);
    if (!result.success) {
        msg.payload = {
            zone_name: cfg.zoneName,
            status: 'FAIL',
            error: result.error,
            timestamp: new Date().toISOString()
        };
    } else {
        const status = (result.actual === cfg.expected) ? 'PASS' : 'FAIL';
        msg.payload = {
            zone_name: cfg.zoneName,
            status,
            actual: result.actual,
            expected: cfg.expected,
            timestamp: new Date().toISOString()
        };
    }
} catch (e) {
    msg.payload = {
        zone_name: cfg.zoneName,
        status: 'FAIL',
        error: `could not parse: ${output}`,
        timestamp: new Date().toISOString()
    };
}

delete msg._cfg;
delete msg._buf;
return msg;
